package com.ichi2.libanki

import org.junit.jupiter.api.Test
import kotlin.test.assertEquals

/**
 * Tests for handling filenames with special characters like '#'.
 * See: https://github.com/ankidroid/Anki-Android/issues/16032
 */
@Suppress("HtmlUnknownTarget", "HtmlRequiredAltAttribute")
class HashFilenameTest {

    /**
     * Verifies that filenames with '#' character are properly parsed and encoded.
     * The '#' should be encoded as '%23' in the file:// URL.
     */
    @Test
    fun `parseSourcesToFileScheme - handles filename with hash character`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"image#1.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/image%231.png">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - handles filename with multiple hash characters`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"file#1#test.jpg\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/file%231%23test.jpg">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - handles filename with hash and other special chars`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"photo#2024@home.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/photo%232024@home.png">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - handles filename with hash and percent`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"m#gent%nki.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/m%23gent%25nki.png">""", result)
    }

    @Test
    fun `getFileUri - properly encodes hash character`() {
        val uri = getFileUri("/storage/media/test#image.png")
        assertEquals("file:////storage/media/test%23image.png", uri.toString())
    }

    @Test
    fun `parseVideos - handles video filename with hash character`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseVideos("[sound:video#1.mp4]", mediaDir)
        assertEquals("""<video src="file:///$mediaDir/video%231.mp4" controls controlsList="nodownload"></video>""", result)
    }
}
"}

